import React, { useState } from "react";

export default function AddGoalFundScreen({ goal, onBack, onUpdateGoal }) {
  const [amount, setAmount] = useState("");

  const handleAdd = () => {
    const num = Number(amount);
    if (num <= 0) return;

    const updatedGoal = { ...goal, current: goal.current + num };
    onUpdateGoal(updatedGoal);
    onBack(); // go back to GoalDetailsScreen
  };

  return (
    <div className="p-6 min-h-screen flex flex-col">
      <button onClick={onBack} className="mb-6 text-gray-500">
        ← Back
      </button>

      <h2 className="text-2xl font-bold mb-4">Add Funds to {goal.title}</h2>

      <input
        type="number"
        placeholder="Amount"
        value={amount}
        onChange={(e) => setAmount(e.target.value)}
        className="mb-4 p-3 rounded-xl border border-gray-300"
      />

      <button
        onClick={handleAdd}
        className="mt-auto py-3 bg-emerald-500 text-white rounded-xl font-bold"
      >
        Add Funds
      </button>
    </div>
  );
}
